mapper.select:
SELECT cr.record_id, cr.appointment_id, cr.student_id, su.real_name as student_name, cr.counselor_id, cu.real_name as counselor_name, cr.record_date, cr.session_number, cr.presenting_problem, cr.session_content, LEFT(cr.session_content, 100) as summary, cr.counselor_observations, cr.intervention_methods, cr.homework_assignment, cr.next_session_plan, cr.counselor_notes, cr.handwritten_record_url, cr.confidential_level, cr.record_status, cr.created_at, cr.updated_at FROM consultation_record cr LEFT JOIN user su ON cr.student_id = su.user_id LEFT JOIN counselor_info ci ON cr.counselor_id = ci.counselor_id LEFT JOIN user cu ON ci.counselor_id = cu.user_id
AND cr.counselor_id = #{query.counselorId}
AND cr.student_id = #{query.studentId}
AND cr.appointment_id = #{query.appointmentId}
AND cr.record_status = #{query.recordStatus}
AND cr.record_date >= #{query.startDate}
AND cr.record_date <= #{query.endDate}
ORDER BY cr.record_date DESC, cr.created_at DESC
